const request = $input.first().json;
const rawHeaders = (request.headers && typeof request.headers === 'object' && !Array.isArray(request.headers)) ? request.headers : {};
const headers = Object.fromEntries(
  Object.entries(rawHeaders).map(([key, value]) => [String(key).toLowerCase(), value])
);
const sanitizedHeaders = Object.fromEntries(
  Object.entries(rawHeaders).filter(([key]) => {
    const normalizedKey = String(key).toLowerCase();
    return normalizedKey !== 'x-api-key' && normalizedKey !== 'authorization';
  })
);
const sanitizedRequest = {
  ...request,
  headers: sanitizedHeaders
};
const headerValue = (value) => Array.isArray(value) ? String(value[0] || '').trim() : String(value || '').trim();
const expectedApiKey = String($env.N8N_WEBHOOK_API_KEY || '').trim();
const xApiKey = headerValue(headers['x-api-key']);
const authorization = headerValue(headers.authorization);
const bearerMatch = authorization.match(/^Bearer\s+(.+)$/i);
const bearerToken = bearerMatch ? String(bearerMatch[1] || '').trim() : '';
const matchedXApiKey = Boolean(expectedApiKey) && xApiKey === expectedApiKey;
const matchedBearer = Boolean(expectedApiKey) && bearerToken === expectedApiKey;
const authenticated = matchedXApiKey || matchedBearer;

if (authenticated) {
  return [{
    json: {
      ...sanitizedRequest,
      webhook_auth: {
        authenticated: true,
        header: matchedXApiKey ? 'X-API-Key' : 'Authorization'
      }
    },
    pairedItem: {
      item: 0
    }
  }];
}

const message = 'Unauthorized: Invalid or missing API key';

return [{
  json: {
    ...sanitizedRequest,
    status: 'error',
    message,
    code: 401,
    webhook_auth: {
      authenticated: false
    }
  },
  pairedItem: {
    item: 0
  }
}];

const input = $input.first().json.body || {};

const tenantId = String(input.tenant_id || '').trim();
const scope = String(input.scope || '').trim();
const query = String(input.query || '').trim();
const requestedK = Number(input.k);
const k = Number.isFinite(requestedK) && requestedK > 0
  ? Math.max(1, Math.min(Math.floor(requestedK), 50))
  : 5;

if (!tenantId || !scope || !query) {
  return [{
    json: {
      error: 'Missing required fields: tenant_id, scope, query'
    }
  }];
}

const requestId = String(input.request_id || '').trim() || `req-${Date.now()}-${Math.random().toString(36).slice(2,8)}`;

return [{
  json: {
    tenant_id: tenantId,
    scope,
    query,
    k,
    request_id: requestId
  }
}];

const data = $input.first().json;

if (data.error) {
  return [{
    json: {
      status: 'error',
      message: data.error
    }
  }];
}

return [{
  json: data
}];

const crypto = require('crypto');

const validated = $('Check Validation').first().json;

if (validated.status === 'error') {
  return [{ json: validated }];
}

const response = $input.first().json;
const responseResult = (response && typeof response.result === 'object' && !Array.isArray(response.result))
  ? response.result
  : null;
const rootPolicy = (response && typeof response === 'object' && !Array.isArray(response) && (
  typeof response.decision === 'string' ||
  typeof response.allow === 'boolean' ||
  typeof response.policy_id === 'string' ||
  typeof response.policy_version === 'string'
))
  ? response
  : null;
const candidatePolicy = responseResult || rootPolicy;

const fallbackPolicy = {
  policy_id: 'fallback',
  policy_version: 'fallback',
  decision: 'deny',
  allow: false,
  requires_approval: true,
  risk_score: 0,
  reasons: ['invalid_policy_response']
};

const policy = candidatePolicy || fallbackPolicy;
const decision = String(policy.decision || '').trim() || 'deny';

const buildApproval = () => {
  if (decision !== 'requires_approval') {
    return null;
  }

  const signingSecret = String($env.N8N_ENCRYPTION_KEY || '').trim();
  if (!signingSecret) {
    return null;
  }

  const signedEnvelope = {
    request_id: validated.request_id || null,
    policy: {
      policy_id: String(policy.policy_id || '').trim() || null,
      policy_version: String(policy.policy_version || '').trim() || null,
      decision,
      allow: Boolean(policy.allow),
      requires_approval: true,
      risk_score: Number.isFinite(Number(policy.risk_score))
        ? Math.round(Number(policy.risk_score))
        : null,
      reasons: Array.isArray(policy.reasons)
        ? policy.reasons.map((reason) => String(reason))
        : []
    },
    approval: {
      endpoint: '/webhook/policy/approval',
      method: 'POST'
    }
  };

  const serializedEnvelope = JSON.stringify(signedEnvelope);
  const signature = crypto.createHmac('sha256', signingSecret).update(serializedEnvelope).digest('hex');

  return {
    ...signedEnvelope.approval,
    token: `${Buffer.from(serializedEnvelope).toString('base64url')}.${signature}`
  };
};

const approval = buildApproval();

if (decision !== 'allow') {
  return [{
    json: {
      status: 'error',
      message: decision === 'requires_approval' ? 'Policy requires approval' : 'Policy denied',
      request_id: validated.request_id,
      policy: {
        ...policy,
        decision
      },
      approval
    }
  }];
}

return [{
  json: {
    ...validated,
    policy: {
      ...policy,
      decision
    }
  }
}];

const fs = require('fs');

// Load PCA model
const pca = JSON.parse(fs.readFileSync('/workspace/pca_model.json', 'utf8'));

const response = $input.first().json;
const embedding = response?.embedding?.values;

if (!Array.isArray(embedding) || embedding.length === 0) {
  throw new Error('Invalid embedding response from Gemini');
}

// PCA transformation
const mean = pca.mean;
const components = pca.components;

// Center the embedding
const centered = embedding.map((v, i) => v - mean[i]);

// Project onto principal components
const reduced = components.map(component =>
  component.reduce((sum, weight, i) => sum + weight * centered[i], 0)
);

const original = $('Check Policy').first().json;

return [{
  json: {
    ...original,
    embedding: `[${reduced.join(',')}]`
  }
}];

const searchResults = $('Search Vectors').all().map((item) => item.json);
const original = $('Check Policy').first().json;

const rankedResults = searchResults.map((r, index) => {
  const distance = Number(r.cosine_distance);
  const similarity = Number.isFinite(distance)
    ? Math.max(0, Math.min(1, 1 - distance))
    : null;

  return {
    id: r.id,
    rank: index + 1,
    scope: r.scope,
    content: r.content,
    tags: r.tags,
    source: r.source,
    created_at: r.created_at,
    cosine_distance: Number.isFinite(distance) ? distance : null,
    similarity_score: similarity,
  };
});

const response = {
  status: 'success',
  mode: 'vector_cosine',
  request_id: original.request_id,
  query: original.query,
  tenant_id: original.tenant_id,
  scope: original.scope,
  k: original.k,
  policy: original.policy || null,
  results_count: rankedResults.length,
  results: rankedResults,
  timestamp: new Date().toISOString()
};

return [{ json: response }];
